import { Option } from 'effect';
import { expect, test } from 'vitest';

test('Option.some wraps a value', () => {
  const opt = Option.some(42);
  expect(Option.isSome(opt)).toBe(true);
  expect(Option.getOrElse(opt, () => 0)).toBe(42);
});

test('Option.none represents absence', () => {
  const opt = Option.none();
  expect(Option.isNone(opt)).toBe(true);
  expect(Option.getOrElse(opt, () => 0)).toBe(0);
});

test('Option.map transforms the value', () => {
  const opt = Option.some(5);
  const doubled = Option.map(opt, (n) => n * 2);
  expect(Option.getOrElse(doubled, () => 0)).toBe(10);
});
